from pydantic_ai import tool

@tool
async def fact_check(claims: List[str]) -> dict:
    """Verify factual claims against search APIs"""
    verified = []
    for claim in claims:
        # Mock search verification
        score = 0.95 if 'apple' in claim.lower() else 0.7
        verified.append({"claim": claim, "verified": score > 0.9, "confidence": score})
    return {"all_verified": all(v['verified'] for v in verified), "details": verified}

import re
from pydantic import validator

class SEOValidator:
    @staticmethod
    def validate_seo(content: GeneratedContent) -> bool:
        body_text = ' '.join(block.text for block in content.body)
        keyword_density = len(re.findall('AI|content', body_text, re.I)) / len(body_text.split())
        readability = len(body_text.split()) / len(body_text) > 0.12  # >8 chars avg
        return keyword_density > 0.01 and readability and content.seo_score >= 0.8
